import math

import pytest

from shapes import circle_area, non_negative, rectangle_area


def test_rectangle_area():
    assert rectangle_area(2, 3) == 6


def test_rectangle_area_unit(unit_square):
    width, height = unit_square
    assert rectangle_area(width, height) == 1


def test_circle_area():
    assert circle_area(1) == math.pi


def test_rejects_negative():
    with pytest.raises(ValueError):
        non_negative(-1)


class TestRectangle:
    def test_large(self):
        assert rectangle_area(10, 10) == 100
